class Solution:
    def clumsy(self, n: int) -> int:
        res, op, v = n, '-', n - 1
        while v > 0:
            if op == '-':
                res -= v
                op, v = '*', v - 1
            elif op == '*':
                res *= v
                op, v = '/', v - 1
            elif op == '/':
                res = res // v
                op, v = '+', v - 1
            else:
                res += v
                op, v = '-', v - 1
        return res

